import React, { useState } from 'react';
import { User, Dumbbell, Award, Flame, Trash2, PlusCircle, Filter, ShieldAlert } from 'lucide-react';

const FitStackSema = () => {
  // --- SEMA'NIN STATE YÖNETİMİ ---
  const [isRegistered, setIsRegistered] = useState(false); // Reg 1
  const [points, setPoints] = useState(0); // Reg 11
  const [streak, setStreak] = useState(5); // Reg 15 (Örnek başlangıç değeri)
  const [activeFilter, setActiveFilter] = useState('Hepsi'); // Reg 7
  const [workouts, setWorkouts] = useState([
    { id: 101, name: 'Sema - Sabah Koşusu', level: 'Başlangıç', date: '25 Mart' },
    { id: 102, name: 'Sema - Kuvvet Antrenmanı', level: 'İleri', date: '26 Mart' },
  ]); // Reg 9 & 17 için liste

  // --- SEMA'NIN FONKSİYONLARI ---

  // Gereksinim 1: Kullanıcı Kaydı (POST /users/register)
  const handleRegister = (e) => {
    e.preventDefault();
    setIsRegistered(true);
    alert("Kullanıcı kaydı Sema tarafından başarıyla oluşturuldu! (Reg 1)");
  };

  // Gereksinim 5: Hesap Silme (DELETE /users/profile)
  const deleteAccount = () => {
    if(window.confirm("Hesabınızı silmek istediğinize emin misiniz? Bu işlem geri alınamaz.")) {
      alert("Hesabınız sistemden silindi. (Reg 5)");
      setIsLogged(false);
    }
  };

  // Gereksinim 9 & 11: Antrenman Kaydı Oluşturma & Puan Kazanma
  const addWorkout = () => {
    const newW = { id: Date.now(), name: 'Sema - Yeni Antrenman', level: 'Orta', date: 'Bugün' };
    setWorkouts([newW, ...workouts]);
    setPoints(points + 100); // Gereksinim 11: Puan artışı
    alert("Antrenman kaydedildi! +100 Puan kazandınız. (Reg 9 & 11)");
  };

  // Gereksinim 17: Antrenman Kaydını Silme (DELETE /workouts/{id})
  const removeWorkout = (id) => {
    setWorkouts(workouts.filter(w => w.id !== id));
    alert("Antrenman kaydı Sema tarafından silindi. (Reg 17)");
  };

  // --- ARAYÜZ ---

  // Kayıt Ekranı (Reg 1)
  if (!isRegistered) {
    return (
      <div className="min-h-screen bg-[#020617] flex items-center justify-center p-6">
        <div className="bg-[#0f172a] border border-[#1e293b] p-10 rounded-[3rem] w-full max-w-md shadow-2xl">
          <h2 className="text-3xl font-black text-[#d9f99d] italic mb-8 text-center">FITSTACK.</h2>
          <form onSubmit={handleRegister} className="space-y-4">
            <input type="text" placeholder="Ad Soyad" className="w-full bg-[#1e293b] p-4 rounded-2xl text-white outline-none focus:ring-2 focus:ring-[#d9f99d]" required />
            <input type="email" placeholder="E-posta" className="w-full bg-[#1e293b] p-4 rounded-2xl text-white outline-none focus:ring-2 focus:ring-[#d9f99d]" required />
            <button type="submit" className="w-full bg-[#d9f99d] text-[#020617] font-black py-4 rounded-2xl hover:bg-[#c3e683] transition-all uppercase">
              Kayıt Ol (Reg 1)
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-100 p-8 font-sans">
      <div className="max-w-6xl mx-auto">

        {/* HEADER: Reg 11 & 15 */}
        <header className="flex justify-between items-center mb-16 border-b border-[#1e293b] pb-8">
          <div>
            <h1 className="text-5xl font-black text-white italic">FITSTACK<span className="text-[#d9f99d]">.</span></h1>
            <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-2">Sema Engineering Dashboard</p>
          </div>
          <div className="flex gap-4">
            <div className="bg-[#0f172a] border border-[#1e293b] p-4 rounded-3xl flex items-center gap-4">
              <Flame className="text-orange-500" />
              <div>
                <p className="text-[10px] text-slate-500 font-bold uppercase">Günlük Seri (Reg 15)</p>
                <p className="font-black text-xl text-white">{streak} GÜN</p>
              </div>
            </div>
            <div className="bg-[#d9f99d] p-4 rounded-3xl flex items-center gap-4 text-[#020617] shadow-xl shadow-[#d9f99d]/10">
              <Award />
              <div>
                <p className="text-[10px] opacity-70 font-bold uppercase">Toplam Puan (Reg 11)</p>
                <p className="font-black text-xl">{points}</p>
              </div>
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">

          {/* SOL PANEL: Reg 3, 5, 13 */}
          <div className="space-y-6">
            <section className="bg-[#0f172a] border border-[#1e293b] p-8 rounded-[2.5rem]">
              <h2 className="text-lg font-bold mb-6 flex items-center gap-3"><User className="text-[#d9f99d]" /> Profil Bilgileri (Reg 3)</h2>
              <div className="space-y-4 mb-8">
                <div className="bg-[#1e293b] p-4 rounded-2xl">
                  <p className="text-[10px] text-slate-500 font-bold uppercase">Kullanıcı</p>
                  <p className="font-bold">Sema Yılmaz</p>
                </div>
                <button onClick={deleteAccount} className="w-full py-4 text-xs font-black text-red-500 hover:bg-red-500/5 rounded-2xl border border-red-500/20 transition-all uppercase tracking-widest">
                  Hesabı Sil (Reg 5)
                </button>
              </div>
            </section>

            <section className="bg-[#0f172a] border border-[#1e293b] p-8 rounded-[2.5rem]">
              <h2 className="text-lg font-bold mb-4">Kazanılan Rozetler (Reg 13)</h2>
              <div className="flex gap-3">
                <div title="Puan Barajı Rozeti" className="w-12 h-12 bg-[#1e293b] border border-[#d9f99d]/30 rounded-2xl flex items-center justify-center text-xl">🏆</div>
                <div title="Seri Ustası Rozeti" className="w-12 h-12 bg-[#1e293b] border border-slate-700 rounded-2xl flex items-center justify-center text-xl opacity-30">🔥</div>
              </div>
            </section>
          </div>

          {/* SAĞ PANEL: Reg 7, 9, 17 */}
          <div className="lg:col-span-2 space-y-6">
            <section className="bg-[#0f172a] border border-[#1e293b] p-10 rounded-[3rem]">
              <div className="flex justify-between items-center mb-10">
                <h2 className="text-2xl font-black italic uppercase tracking-tighter">Antrenmanlar</h2>
                <div className="flex bg-[#1e293b] p-1.5 rounded-2xl">
                  {['Hepsi', 'Başlangıç', 'Orta', 'İleri'].map(lvl => (
                    <button key={lvl} onClick={() => setActiveFilter(lvl)} className={`px-5 py-2 rounded-xl text-xs font-black transition-all ${activeFilter === lvl ? 'bg-[#d9f99d] text-[#020617]' : 'text-slate-500 hover:text-white'}`}>
                      {lvl}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                {workouts.filter(w => activeFilter === 'Hepsi' || w.level === activeFilter).map(w => (
                  <div key={w.id} className="flex justify-between items-center p-6 bg-[#020617]/50 border border-[#1e293b] rounded-3xl hover:border-[#d9f99d]/30 transition-all">
                    <div className="flex items-center gap-6">
                      <div className="w-14 h-14 bg-[#1e293b] rounded-2xl flex items-center justify-center text-[#d9f99d]"><Dumbbell /></div>
                      <div>
                        <h4 className="font-bold text-white text-lg">{w.name}</h4>
                        <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">{w.date} • <span className="text-[#d9f99d]">{w.level} (Reg 7)</span></p>
                      </div>
                    </div>
                    <button onClick={() => removeWorkout(w.id)} className="p-3 text-slate-600 hover:text-red-500 transition-colors"><Trash2 size={20} /></button>
                  </div>
                ))}
              </div>

              <button onClick={addWorkout} className="w-full mt-10 py-5 bg-white text-[#020617] font-black rounded-3xl hover:bg-[#d9f99d] transition-all flex items-center justify-center gap-3 uppercase tracking-widest shadow-xl">
                <PlusCircle size={20} /> Yeni Antrenman Kaydet (Reg 9)
              </button>
            </section>
          </div>

        </div>
      </div>
    </div>
  );
};

export default FitStackSema;
